public int[] numberOfLines(int[] widths, String s) {
    int lines = 1;
    int currentPixel = 0;
    for (char c : s.toCharArray()) {
        int letterPixels = widths[c - 'a'];
        if (currentPixel + letterPixels > 100) {
            lines++;
            currentPixel = 0;
        }
        currentPixel += letterPixels;
    }
    return new int[]{lines, currentPixel};
}
```


